// src/hooks/usePhotographers.js
import { useState, useCallback } from "react";

const API_BASE_URL = process.env.REACT_APP_API_URL || "http://localhost:3000/api";

console.log("🔗 API Base URL:", API_BASE_URL);

export const usePhotographers = () => {
  const [photographers, setPhotographers] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);
  const [pagination, setPagination] = useState({
    page: 1,
    limit: 12,
    total: 0,
    totalPages: 0,
  });

  // Search & filter photographers
  const searchPhotographers = useCallback(async (filters) => {
    try {
      setLoading(true);
      setError(null);

      const queryParams = new URLSearchParams();
      Object.entries(filters).forEach(([key, value]) => {
        if (value && value !== "") {
          if (Array.isArray(value)) {
            value.forEach((v) => queryParams.append(key, v));
          } else {
            queryParams.append(key, value);
          }
        }
      });

      const url = `${API_BASE_URL}/photographers/search?${queryParams}`;
      console.log("🌐 Fetching:", url);

      const response = await fetch(url);
      console.log("📦 Response status:", response.status);
      console.log("📦 Response headers:", response.headers);

      if (!response.ok) {
        const errorText = await response.text();
        console.error("❌ Response not ok:", errorText);
        throw new Error(`HTTP ${response.status}: ${errorText}`);
      }

      const data = await response.json();
      console.log("✅ Response data:", data);

      if (data.success) {
        setPhotographers(data.data?.data || []);
        setPagination(data.data?.pagination || {});
      } else {
        setError(data.message || "Unknown error");
      }
    } catch (err) {
      console.error("❌ Error:", err);
      setError(err.message);
    } finally {
      setLoading(false);
    }
  }, []);

  // Get photographer detail
  const getPhotographerDetail = useCallback(async (photographerId) => {
    try {
      setLoading(true);
      setError(null);

      const url = `${API_BASE_URL}/photographers/${photographerId}`;
      console.log("🌐 Fetching:", url);

      const response = await fetch(url);
      console.log("📦 Response status:", response.status);

      if (!response.ok) {
        const errorText = await response.text();
        console.error("❌ Response not ok:", errorText);
        throw new Error(`HTTP ${response.status}`);
      }

      const data = await response.json();
      console.log("✅ Response data:", data);

      if (data.success) {
        return data.data;
      } else {
        setError(data.message || "Unknown error");
        return null;
      }
    } catch (err) {
      console.error("❌ Error:", err);
      setError(err.message);
      return null;
    } finally {
      setLoading(false);
    }
  }, []);

  // Get top photographers
  const getTopPhotographers = useCallback(async (limit = 6) => {
    try {
      setLoading(true);
      setError(null);

      const url = `${API_BASE_URL}/photographers/top?limit=${limit}`;
      console.log("🌐 Fetching:", url);

      const response = await fetch(url);
      console.log("📦 Response status:", response.status);

      if (!response.ok) {
        const errorText = await response.text();
        console.error("❌ Response not ok:", errorText);
        throw new Error(`HTTP ${response.status}`);
      }

      const data = await response.json();
      console.log("✅ Response data:", data);

      if (data.success) {
        setPhotographers(data.data || []);
      } else {
        setError(data.message || "Unknown error");
      }
    } catch (err) {
      console.error("❌ Error:", err);
      setError(err.message);
    } finally {
      setLoading(false);
    }
  }, []);

  // Get available filters
  const getStyles = useCallback(async () => {
    try {
      const url = `${API_BASE_URL}/photographers/styles`;
      console.log("🌐 Fetching styles:", url);

      const response = await fetch(url);
      if (!response.ok) throw new Error(`HTTP ${response.status}`);

      const data = await response.json();
      console.log("✅ Styles:", data);

      return data.success ? data.data || [] : [];
    } catch (err) {
      console.error("❌ Error fetching styles:", err);
      return [];
    }
  }, []);

  const getLocations = useCallback(async () => {
    try {
      const url = `${API_BASE_URL}/photographers/locations`;
      console.log("🌐 Fetching locations:", url);

      const response = await fetch(url);
      if (!response.ok) throw new Error(`HTTP ${response.status}`);

      const data = await response.json();
      console.log("✅ Locations:", data);

      return data.success ? data.data || [] : [];
    } catch (err) {
      console.error("❌ Error fetching locations:", err);
      return [];
    }
  }, []);

  return {
    photographers,
    setPhotographers,
    loading,
    error,
    pagination,
    searchPhotographers,
    getPhotographerDetail,
    getTopPhotographers,
    getStyles,
    getLocations,
  };
};

export default usePhotographers;
